final:
module RefModule (
    input clk,
    input rst,
    output reg [15:0] out
);

wire feedback = out[15] ^ out[13] ^ out[12] ^ out[10];

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
    if (rst)
        out <= 16'b1;
    else
        out <= {out[14:0], feedback};
end

endmodule
